// Filter Plane issues that need syncing to GitLab
// Skip issues that originated from GitLab (prefixed with [GitLab], [Push], [MR], [Comment])
// Skip issues already synced (have external_source = 'gitlab')
// Only sync issues updated in the last 10 minutes

const results = $input.all();
const issues = (results[0]?.json?.results || results[0]?.json || []);

const SYNC_WINDOW_MS = 10 * 60 * 1000; // 10 minutes
const now = Date.now();
const GITLAB_PREFIXES = ['[GitLab]', '[Push]', '[MR ', '[Comment]', '[GitLab Closed]'];

// State ID → GitLab label mapping
const STATE_MAP = {
  'cfc8f7cd-daaf-4d5a-819e-f59b5d3b36c9': { label: 'backlog', open: true },
  '3eaae951-b70c-4b09-8a46-d7094e10ae97': { label: 'todo', open: true },
  '44c20543-a3f6-4769-90fe-56f93342a71a': { label: 'in-progress', open: true },
  'cb7fc63e-8e56-4962-90c9-de3054067c4f': { label: 'done', open: false },
  '0eee9bc5-5cd9-4887-96ff-a77d1e9227ec': { label: 'cancelled', open: false }
};

// Priority mapping
const PRIORITY_MAP = {
  'urgent': 'priority::critical',
  'high': 'priority::high',
  'medium': 'priority::medium',
  'low': 'priority::low',
  'none': ''
};

const toSync = [];

for (const issue of issues) {
  // Skip issues from GitLab
  const name = issue.name || '';
  if (GITLAB_PREFIXES.some(p => name.startsWith(p))) continue;

  // Skip already-synced issues
  if (issue.external_source === 'gitlab') continue;

  // Only sync recently updated issues
  const updatedAt = new Date(issue.updated_at).getTime();
  if (now - updatedAt > SYNC_WINDOW_MS) continue;

  const stateInfo = STATE_MAP[issue.state] || { label: 'backlog', open: true };
  const priorityLabel = PRIORITY_MAP[issue.priority] || '';
  const labels = ['plane-sync', stateInfo.label].filter(Boolean);
  if (priorityLabel) labels.push(priorityLabel);

  // Strip HTML tags for description
  const descHtml = issue.description_html || '';
  const descText = descHtml.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

  toSync.push({
    json: {
      plane_id: issue.id,
      title: `[Plane] ${name}`,
      description: `**Source:** Plane issue ${issue.sequence_id || issue.id}\n\n${descText}`,
      labels: labels.join(','),
      state_action: stateInfo.open ? 'reopen' : 'close',
      state_label: stateInfo.label,
      priority: issue.priority,
      external_id: issue.external_id,
      has_external_id: !!issue.external_id
    }
  });
}

if (toSync.length === 0) {
  return [{ json: { _skip: true, message: 'No issues to sync' } }];
}

return toSync;

// Prepare the PATCH call to write the GitLab issue ID back to Plane
const gitlabIssue = $json;
const planeId = $('Already Synced?').item.json.plane_id;
const gitlabIid = gitlabIssue.iid || gitlabIssue.id;

return {
  json: {
    _patch_url: ($env.PLANE_API_URL || 'http://genai-plane-api.genai.svc.cluster.local:8000') + '/api/v1/workspaces/r-aas/projects/1b0b93eb-5915-4338-bd16-16a04acdb429/issues/' + planeId + '/',
    _patch_body: JSON.stringify({
      external_id: String(gitlabIid),
      external_source: 'gitlab'
    }),
    _plane_token: $env.PLANE_API_TOKEN || '',
    gitlab_iid: gitlabIid,
    plane_id: planeId,
    title: $('Already Synced?').item.json.title
  }
};
